const MANIFEST_TOML: &str = include_str!("../manifest.toml");
const SURFACE_STATUS: &str = "incubating";
const OP_SCAFFOLD_STATUS: &str = "truthful-sample.scaffold_status";
const CAP_SCAFFOLD_STATUS: &str = "truthful-sample.scaffold_status";
const SUPPORTS_STREAMING: bool = false;

// ─────────────────────────────────────────────────────────────────────────────
// Doctor types (connector-local diagnostics)
// ─────────────────────────────────────────────────────────────────────────────

/// Result of a connector doctor check.
#[derive(Debug, Clone, serde::Serialize)]
struct DoctorResult {
    passed: bool,
    checks: Vec<DoctorCheck>,
}

/// A single diagnostic check within a doctor run.
#[derive(Debug, Clone, serde::Serialize)]
struct DoctorCheck {
    name: String,
    passed: bool,
    message: Option<String>,
    critical: bool,
}

impl DoctorResult {
    fn from_checks(checks: Vec<DoctorCheck>) -> Self {
        let passed = checks.iter().filter(|c| c.critical).all(|c| c.passed);
        Self { passed, checks }
    }
}

/// TruthfulSample connector state.
#[derive(Debug)]
pub struct TruthfulSampleConnector {
    base: BaseConnector,
    configured: bool,
    config: Option<TruthfulSampleConfig>,
    runtime: Option<ConnectorRuntime>,
    retry_config: HttpRetryConfig,
    started_at: Instant,
    verifier: Option<CapabilityVerifier>,
}

impl TruthfulSampleConnector {
    /// Create a new connector instance.
    pub fn new() -> Self {
        Self {
            base: BaseConnector::new(ConnectorId::from_static("fcp.truthful-sample")),
            configured: false,
            config: None,
            runtime: None,
            retry_config: HttpRetryConfig::default(),
            started_at: Instant::now(),
