#[async_trait]
impl FcpConnector for TruthfulSampleConnector {
    fn id(&self) -> &ConnectorId {
        &self.base.id
    }

    async fn configure(&mut self, config: serde_json::Value) -> FcpResult<()> {
        let config = TruthfulSampleConfig::from_value(config)?;
        self.retry_config = config.retry.clone();
        let mut runtime_config = ConnectorRuntimeConfig::from_manifest_str(MANIFEST_TOML)
            .map_err(|error| FcpError::Internal {
                message: format!("Embedded manifest timeout defaults are invalid: {error}"),
            })?;
        if let Some(request_timeout_ms) = config.request_timeout_ms {
            runtime_config =
                runtime_config.with_request_timeout(Duration::from_millis(request_timeout_ms));
        }
        if let Some(runtime) = self.runtime.take() {
            runtime.shutdown();
        }
        self.runtime = Some(ConnectorRuntime::new(runtime_config));
        self.config = Some(config);
        self.verifier = None;
        self.configured = true;
        self.base.set_configured(true);
        self.base.set_handshaken(false);
        Ok(())
    }

    async fn handshake(&mut self, req: HandshakeRequest) -> FcpResult<HandshakeResponse> {
        if !self.configured || self.runtime.is_none() {
            return Err(FcpError::NotConfigured);
        }

        self.base.set_handshaken(true);

        // Initialize capability verifier with host key and zone
        self.verifier = Some(CapabilityVerifier::new(
            req.host_public_key,
            req.zone.clone(),
            self.base.instance_id.clone(),
        ));

        let capabilities_granted = req
            .capabilities_requested
            .into_iter()
            .map(|cap| CapabilityGrant {
                capability: cap,
                operation: None,
            })
            .collect();

        Ok(HandshakeResponse {
            status: "accepted".into(),
            capabilities_granted,
            session_id: SessionId::new(),
            manifest_hash: Self::manifest_hash(),
            nonce: req.nonce,
            event_caps: Some(EventCaps {
                streaming: SUPPORTS_STREAMING,
                replay: false,
                min_buffer_events: 0,
                requires_ack: false,
            }),
            auth_caps: None,
            op_catalog_hash: None,
        })
    }

    async fn health(&self) -> HealthSnapshot {
        let mut snapshot = if self.configured {
            HealthSnapshot::ready()
        } else {
            HealthSnapshot::degraded("not configured")
        };
        snapshot.uptime_ms = self.started_at.elapsed().as_millis() as u64;
        snapshot.details = Some(self.scaffold_status_payload(false));
        snapshot
    }

    async fn self_check(&self) -> FcpResult<SelfCheckReport> {
        if !self.configured {
            return Ok(SelfCheckReport::degraded(
                "not_configured",
                "Connector is not configured",
            ));
        }

        let mut report = SelfCheckReport::degraded(
            "incubating_surface",
            "Connector is configured, but only the local scaffold_status operation is implemented",
        );
        report.details = Some(self.scaffold_status_payload(true));
        Ok(report)
    }

    async fn simulate(&self, req: SimulateRequest) -> FcpResult<SimulateResponse> {
        if req.operation.as_str() != OP_SCAFFOLD_STATUS {
            let error = FcpError::InvalidRequest {
                code: 1004,
                message: format!("Unknown operation: {}", req.operation.as_str()),
            };
            return Ok(SimulateResponse::denied(
                req.id,
                error.to_string(),
                error.error_code(),
            ));
        }

        if !self.configured || self.runtime.is_none() {
            return Ok(SimulateResponse::denied(
                req.id,
                "Connector is not configured",
                FcpError::NotConfigured.error_code(),
            ));
        }

        let Some(verifier) = &self.verifier else {
            return Ok(SimulateResponse::denied(
                req.id,
                "Connector handshake not completed",
                FcpError::NotHandshaken.error_code(),
            ));
        };

        let required_cap = CapabilityId::from_static(CAP_SCAFFOLD_STATUS);
        if let Err(error) = verifier.verify(req.capability_token, &required_cap, &req.operation, &[]) {
            let mut response =
                SimulateResponse::denied(req.id, error.to_string(), error.error_code());
            if error.error_code() == "FCP-3001" {
                response =
                    response.with_missing_capabilities(vec![required_cap.as_str().to_string()]);
            }
            return Ok(response);
        }

        // Default V3 simulate: reflect lifecycle/capability gating without side effects.
        // TODO: Add cost estimation, resource availability checks, etc.
        Ok(SimulateResponse::allowed(req.id))
    }

    fn metrics(&self) -> ConnectorMetrics {
        self.base.metrics()
    }

    async fn shutdown(&mut self, _req: ShutdownRequest) -> FcpResult<()> {
        if let Some(runtime) = self.runtime.take() {
            runtime.shutdown();
        }
        self.config = None;
        self.verifier = None;
        self.configured = false;
        self.base.set_configured(false);
        self.base.set_handshaken(false);
        Ok(())
    }

    fn introspect(&self) -> Introspection {
        Introspection {
            operations: vec![self.scaffold_status_operation()],
            events: Vec::new(),
            resource_types: Vec::new(),
            auth_caps: None,
            event_caps: Some(EventCaps {
                streaming: SUPPORTS_STREAMING,
                replay: false,
                min_buffer_events: 0,
                requires_ack: false,
            }),
        }
    }

    async fn invoke(&self, req: InvokeRequest) -> FcpResult<InvokeResponse> {
        if req.operation.as_str() != OP_SCAFFOLD_STATUS {
            return Err(FcpError::InvalidRequest {
                code: 1004,
                message: format!("Unknown operation: {}", req.operation.as_str()),
            });
        }

        self.base.check_ready()?;
        let verifier = self.verifier.as_ref().ok_or(FcpError::NotHandshaken)?;
        let required_cap = CapabilityId::from_static(CAP_SCAFFOLD_STATUS);
        verifier.verify(req.capability_token, &required_cap, &req.operation, &[])?;
        self.enforce_limits(&req.input)?;
        let runtime = self.runtime.as_ref().ok_or(FcpError::NotConfigured)?;
        let ctx = runtime.request_context();
        let policy = self.retry_config.to_retry_policy();
        let include_next_steps = req
            .input
            .get("include_next_steps")
            .and_then(|value| value.as_bool())
            .unwrap_or(true);
        let output = self.scaffold_status_payload(include_next_steps);

        let output = RetryLoop::execute(&ctx, &policy, |attempt| {
            let output = output.clone();
            async move {
                debug!(
                    attempt,
                    operation = OP_SCAFFOLD_STATUS,
                    surface_status = SURFACE_STATUS,
                    "Executing scaffold-status invoke path"
                );
                AttemptOutcome::Success(output)
            }
        })
        .await
        .map_err(|error: TruthfulSampleError| error.to_fcp_error())?;

        Ok(InvokeResponse::ok(req.id, output))
    }

    async fn subscribe(&self, req: SubscribeRequest) -> FcpResult<SubscribeResponse> {
        if !SUPPORTS_STREAMING {
            return Err(FcpError::StreamingNotSupported);
        }


        Ok(SubscribeResponse {
            r#type: "response".into(),
            id: req.id,
            result: SubscribeResult {
                confirmed_topics: req.topics,
                cursors: std::collections::HashMap::new(),
                replay_supported: false,
                buffer: None,
            },
        })
    }

    async fn unsubscribe(&self, _req: UnsubscribeRequest) -> FcpResult<()> {

        Ok(())
    }
}


